const authService = require('../services/auth.service');
const { signToken } = require('../utils/jwt');

/**
 * Registro de administrador
 * POST /api/auth/register-admin
 */
const registerAdmin = async (req, res) => {
  try {
    const { nombre, correo, password, identificacion } = req.body;

    // Registrar administrador
    const user = await authService.registerAdmin({
      nombre,
      correo,
      password,
      identificacion,
    });

    res.status(201).json({
      user,
    });
  } catch (error) {
    const statusCode = error.statusCode || 500;
    res.status(statusCode).json({
      error: error.message || 'Error al registrar administrador',
    });
  }
};

/**
 * Login de usuario
 * POST /api/auth/login
 */
const login = async (req, res) => {
  try {
    const { correo, password } = req.body;

    // Autenticar usuario
    const user = await authService.login(correo, password);

    // Generar token JWT
    const token = signToken({
      id_usuario: user.id_usuario,
      nombre: user.nombre,
      id_rol: user.id_rol,
    });

    res.status(200).json({
      token,
      user,
    });
  } catch (error) {
    const statusCode = error.statusCode || 500;
    res.status(statusCode).json({
      error: error.message || 'Error al iniciar sesión',
    });
  }
};

/**
 * Obtener información del usuario autenticado
 * GET /api/auth/me
 */
const getMe = async (req, res) => {
  try {
    // El usuario ya está en req.user gracias al middleware authenticate
    res.status(200).json({
      user: req.user,
    });
  } catch (error) {
    res.status(500).json({
      error: 'Error al obtener información del usuario',
    });
  }
};

module.exports = {
  registerAdmin,
  login,
  getMe,
};
